//预留文件
$(function () {
    //头部导航
    $("#navbar ul li.zlm").hover(
        function(){
            $(this).children('.menulist').attr('style','display:block');
            $(this).children('.mn').addClass("active");
        },
        function(){
            $(this).children('.menulist').hide();
            $(this).children('.mn').removeClass("active");
        }
    );

});